mapper.select:
SELECT *,
       ST_Distance_Sphere(POINT(court_lng, court_lat), POINT(#{param.lng}, #{param.lat})) AS distance_meters
FROM rally_meetup

    city_code = #{param.cityCode}
    AND status = 'OPEN'
    AND end_time > NOW()
    AND court_lng IS NOT NULL AND court_lat IS NOT NULL

        AND match_type = #{param.matchType}


        AND start_time >= #{param.startTimeFrom}


        AND start_time <= #{param.startTimeTo}



        AND (level_min IS NULL OR level_min <= #{param.levelMax})
        AND (level_max IS NULL OR level_max >= #{param.levelMin})



        AND ST_Distance_Sphere(POINT(court_lng, court_lat), POINT(#{param.lng}, #{param.lat})) <= #{param.radiusMeters}


ORDER BY distance_meters ASC, biz_id ASC

